import * as FunctionUtil from '@/common/FunctionUtil';

const devices = ['스캐너', '드론돔', '레이더', '재머', 'EO/IR'];
const connetionList = [];

let rNum = 0;
for (let index = 1; index < 45; index++) {
    rNum = FunctionUtil.randomNum(0, devices.length - 1);

    connetionList.push({
        idx: index,
        category: rNum,
        name: `${devices[rNum]}${index}`,
        method: 'TCP',
        deviceIp: `127.0.0.${index}`,
        devicePort: '13001, 13002',
        powerIp: `127.0.0.${index}`,
        powerPort: '17000',
        pcPort: '-',
        device: devices[rNum],
        version: 'V1.4.2',
        state: index % 2 === 0 ? true : false,
        // devices[rNum]
    });
}

export { devices, connetionList };
