import * as DateUtil from "@/common/DateUtil";

const uuid = () => {
    function s4() {
        return ((1 + Math.random()) * 0x10000 | 0).toString(16).substring(1);
    }
    return s4() + s4() + '-' + s4() + '-' + s4() + '-' + s4() + '-' + s4() + s4() + s4();
}

const groupBy = key => array =>
    array.reduce((objectsByKeyValue, obj) => {
        const value = obj[key];
        objectsByKeyValue[value] = (objectsByKeyValue[value] || []).concat(obj);
        return objectsByKeyValue;
    }, {});

const getObjectByValue = (array, key, value) => {
    return array.filter(function(object) {
        return object[key] === value;
    });
};

const getObjectIndexByValue = (array, key, value) => {
  return array.findIndex(function(object) {
      return object[key] === value;
  });
};

const getKeyByValue = (object, value) => {
    return Object.keys(object).find(key => object[key] === value);
}

const getValueByKeyValues = (array, key1, value1, key2, value2, targetKeyName) => {
    return array.filter(function(object) {
        let temp = (object[key1] === value1 && object[key2] === value2);
        return temp != null ? temp[targetKeyName] : null;
    });
};


const excelDownload = (headerInfo, objArray, fileName) => {
    let array = typeof objArray != 'object' ? JSON.parse(objArray) : objArray;
    let str = '';

    let line = '';
    for (let i = 0; i < headerInfo.length; i++) {
        line += headerInfo[i] + ',';
    }
    line.slice(0, line.Length - 1);
    str += line + '\r\n';

    for (let i = 0; i < array.length; i++) {
        let line = '';
        for (let index in array[i]) {
            line += array[i][index] + ',';
        }
        line.slice(0, line.Length - 1);
        str += line + '\r\n';
    }

    let element = document.createElement('a');
    let blob = new Blob(["\ufeff" + str], { type: 'text/csv;charset=utf-8;' }); // 한글깨짐방지: \ufeff
    let url = URL.createObjectURL(blob);
    element.href = url;
    element.setAttribute('download', fileName + '_' + DateUtil.getCurrentTimestamp() + '.csv');
    element.click();
    // document.body.removeChild(element);
}

