<template>
    <div class="popup_wrap">
        <div class="popup_content">
            <p class="popup_title">추가</p>
            <table>
                <colgroup>
                    <col width="102" />
                    <col width="*" />
                    <col width="102" />
                    <col width="*" />
                </colgroup>
                <tbody>
                    <tr>
                        <th>이 름</th>
                        <td>
                            <v-text-field v-model="model.DEVICE_NAME" outlined hide-details class="white" @keyup="validationCheck()" />
                        </td>
                        <th>연결방식</th>
                        <td>
                            <v-select
                                outlined
                                return-object
                                v-model="selectedConnectType"
                                :items="connectTypeList"
                                item-text="label"
                                item-value="value"
                                hide-details
                                class="white"
                                @change="validationCheck()"
                            />
                        </td>
                    </tr>
                    <tr>
                        <th>장치 IP</th>
                        <td><v-text-field v-model="model.DEVICE_IP" outlined hide-details class="white" @keyup="validationCheck()" /></td>
                        <th>장치 Port</th>
                        <td>
                            <v-text-field v-model="model.DEVICE_PORT" outlined hide-details class="white" @keyup="validationCheck()" />
                            <p class="txt_setting">* '콤마(,)'를 이용해 복수 개 설정 가능</p>
                        </td>
                    </tr>
                    <tr>
                        <th>전원 IP</th>
                        <td><v-text-field v-model="model.POWER_IP" outlined hide-details class="white" @keyup="validationCheck()" /></td>
                        <th>전원 Port</th>
                        <td><v-text-field v-model="model.POWER_PORT" outlined hide-details class="white" @keyup="validationCheck()" /></td>
                    </tr>
                    <tr>
                        <th>PC Port</th>
                        <td>
                            <v-text-field v-model="model.PC_PORT" outlined hide-details class="white" @keyup="validationCheck()" />
                            <p class="txt_setting">* 미입력시 자동으로 설정</p>
                        </td>
                        <th>장 비</th>
                        <td>
                            <v-select
                                outlined
                                return-object
                                v-model="selectedDeviceType"
                                :items="deviceTypeList"
                                item-text="label"
                                item-value="value"
                                hide-details
                                class="white"
                                @change="validationCheck()"
                            />
                        </td>
                    </tr>
                </tbody>
            </table>
            <div class="btn_area">
                <v-btn color="primary" :disabled="!this.validation" elevation="3" @click="doSave">확인</v-btn>
                <v-btn outlined plain elevation="3" @click="popupCloseNo">취소</v-btn>
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>
<script>
import * as DateUtil from "@/common/DateUtil";
import * as JsonUtil from "@/common/JsonUtil";
import * as LogUtil from "@/common/LogUtil";
import * as Device from "@/rest/Device";

import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
      AlertModal
    },
    data: () => ({
      alertModalParams: { isOpened: false, title: '', message: ''},
      deviceTypeList: [
        { value: 'D', label: '드론돔' },
        { value: 'R', label: '레이더' },
        { value: 'J', label: '재머' },
        { value: 'S', label: '스캐너' },
        { value: 'E', label: 'EO/IR' },
        { value: 'P', label: '스푸퍼' },
      ],
      selectedDeviceType: null,
      connectTypeList: [
        { value: 'U', label: 'UDP' },
        { value: 'T', label: 'TCP' },
        { value: 'S', label: 'Serial' },
      ],
      selectedConnectType: null,
      validation: false,
      model: {
        DEVICE_TYPE: null,
        CONNECT_TYPE: null,
        DEVICE_NAME: null,
        DEVICE_IP: null,
        DEVICE_PORT: null,
        POWER_IP: null,
        POWER_PORT: null,
        PC_PORT: null,
        VERSION: null,
        STATUS: null,
      },
    }),
    props: ['selectInfo'],
    mounted() {
      if (this.selectInfo.DEVICE_ID) {
        this.model = this.selectInfo;
        this.selectedDeviceType = JsonUtil.getObjectByValue(this.deviceTypeList, 'value', this.selectInfo.DEVICE_TYPE)[0];
        this.selectedConnectType = JsonUtil.getObjectByValue(this.connectTypeList, 'value', this.selectInfo.CONNECT_TYPE)[0];
        delete this.model.CREATED;
        this.model.UPDATED = DateUtil.getTimestamp(this.model.UPDATED);

        LogUtil.debug('ConnectionUpdate: mounted(): this.model=', this.model);
        this.validation = true;
      }
    },
    methods: {
      showAlertModal(msg) {
        this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
      },
      doSave() {
        this.model.DEVICE_TYPE = this.selectedDeviceType.value;
        this.model.CONNECT_TYPE = this.selectedConnectType.value;
        LogUtil.debug('ConnectionUpdate: doSave(): this.model=', this.model);
        
        Device.save(this.model).then(res => {
          if(res.data.RES_CODE>=0) {
            LogUtil.debug('AccountModify: doSave(): res.data.RES_CODE=', res.data.RES_CODE);
            this.$emit('popupCloseYes', false);
          } else {
            this.showAlertModal(res.data.RES_MSG);
          }
        }).catch(e => {
          LogUtil.error("error=", e);
          this.showAlertModal(e);
        }).finally(() => {
        });
      },
      popupCloseYes() {
        // 확인 일 경우 추가 / 수정 의 내용을 서버에 저장 -> SystemConnection.vue 에서는 리스트를 새로 가져와야함 (업데이트)
        this.$emit('popupCloseYes', false);
      },
      popupCloseNo() {
        // 확인 일 경우 추가 / 수정 의 내용을 서버에 저장 -> SystemConnection.vue 에서는 리스트를 새로 가져와야함 (업데이트)
        this.$emit('popupCloseNo', false);
      },
      validationCheck() {
        this.validation =
          this.selectedDeviceType
          && this.selectedConnectType
          && this.model.DEVICE_NAME
          && this.model.DEVICE_IP
          && this.model.DEVICE_PORT
          && this.model.POWER_IP
          && this.model.POWER_PORT
          && this.model.PC_PORT;
          LogUtil.debug('ConnectionUpdate: validationCheck(): this.validation=', this.validation);
      },
  },
};
</script>

<style lang="scss" scoped>
.popup_wrap {
    margin: 0 10px;
    .popup_content {
        width: 800px;
        height: 420px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            margin: 0 10px;
            font: {
                size: 20px;
            }
            border-bottom: 2px solid #ccc;
        }
        table {
            width: 100%;
            margin: 25px 0 0;
            /* padding: 0 40px; */
            th,
            td {
                height: 68px;
                vertical-align: top;
            }
            th {
                padding: 8px 10px 0 0;
                font: {
                    size: 15px;
                    weight: 500;
                }
                text-align: right;
            }
            td {
                text-align: left;
                .txt_setting {
                    margin: 5px 0 0;
                    font: {
                        size: 12px;
                        weight: 500;
                    }
                    color: #e10000;
                }
            }
            .v-input,
            input[type='text'] {
                width: 250px;
                height: 38px;
                border: 1px solid #999;
                border-radius: 6px;
            }
        }
        .btn_area {
            @include centerAlign();
            margin: 0 10px;
            border-top: 2px solid #ccc;
            button + button {
                margin-left: 14px;
            }
        }
    }
}
</style>
