<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="btn_area">
                <div class="crud">
                    <v-btn
                        elevation="3"
                        color="primary"
                        outlined
                        @click="
                            () => {
                                selectInfo = {};
                                this.$forceUpdate();
                                popupUpdateView(true);
                            }
                        "
                    >
                        추가
                    </v-btn>
                    <v-btn elevation="3" color="primary" :disabled="!this.selectInfo.DEVICE_ID" outlined @click="popupUpdateView(true)"> 수정 </v-btn>
                    <v-btn elevation="3" color="primary" :disabled="!this.selectInfo.DEVICE_ID" outlined @click="popupDeleteView(true)"> 삭제 </v-btn>
                </div>
                <div class="tab">
                    <v-btn
                        :class="selectedDeviceType === 'A' ? 'btn_all' : 'btn_tab'"
                        @click="onDeviceTypeSelected('A')"
                        :outlined="cateNum !== -1"
                        :color="selectedDeviceType === 'A' ? '#FFCC00' : '#666'"
                        primary
                        elevation="3"
                        >전체보기</v-btn
                    >
                    <v-btn
                        v-for="(item, i) in deviceTypeList"
                        :key="`${i}`"
                        :class="selectedDeviceType === item.value ? 'btn_tab' : 'btn_all'"
                        @click="onDeviceTypeSelected(item.value)"
                        :outlined="cateNum !== i"
                        :color="selectedDeviceType === item.value ? '#FFCC00' : '#666'"
                        primary
                        elevation="3"
                        >{{ item.label }}</v-btn
                    >
                </div>
            </div>
            <v-data-table
                :headers="headers"
                :items="dataList"
                :items-per-page="pageSize"
                no-data-text="데이터가 존재하지 않습니다."
                hide-default-footer
            >
                <template #item="{ item }">
                    <tr @click="selectList(item)" :class="selectInfo.DEVICE_ID === item.DEVICE_ID ? 'active' : ''">
                        <td>{{ item.DEVICE_NAME }}</td>
                        <td>{{ item.CONNECT_TYPE }}</td>
                        <td>{{ item.DEVICE_IP }}</td>
                        <td>{{ item.DEVICE_PORT }}</td>
                        <td>{{ item.POWER_IP }}</td>
                        <td>{{ item.POWER_PORT }}</td>
                        <td>{{ item.PC_PORT }}</td>
                        <td>{{ getDeviceType(item.DEVICE_TYPE) }}</td>
                        <td>{{ item.VERSION }}</td>
                        <td class="device_state">
                            <img v-if="item.STATUS === 'O'" src="@/assets/setting/device_state_on.svg" />
                            <img v-else src="@/assets/setting/device_state_off.svg" />
                        </td>
                    </tr>
                </template>
            </v-data-table>
            <v-col class="pagination">
                <v-pagination v-model="pageNo" :length="numOfPages" :total-visible="pageSize" />
            </v-col>
        </div>
        <ConnectionUpdatePopup v-if="isUpdatePopupOpen" :selectInfo="selectInfo" @popupCloseYes="onUpdate" @popupCloseNo="onUpdateCancel" />
        <DeleteConfirmPopup v-if="isDeletePopupOpen" :defaultView="true" @popupCloseYes="onDelete" @popupCloseNo="onDeleteCancel" />

        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
import Obj from './SystemConnection.js';
export default Obj;
</script>

<style lang="scss" scoped>
.content {
    .btn_area {
        height: 38px;
        margin-bottom: 30px;
        & > div {
            @include hCenterAlign();
            height: inherit;
            &.crud {
                float: left;
                button + button {
                    margin-left: 4px;
                }
            }
            &.tab {
                float: right;
                button {
                    font: {
                        size: 15px;
                    }
                    &.v-btn--is-elevated {
                        font: {
                            weight: 600;
                        }
                    }
                }
                .btn_tab {
                    margin-left: 11px;
                    color: $color-btn06;
                    caret-color: $color-btn06;
                    &.v-btn--is-elevated {
                        color: $color-main04;
                    }
                }
                .btn_all {
                    margin-left: 11px;
                    color: $color-btn06;
                    caret-color: $color-btn06;
                    &.v-btn--is-elevated {
                        color: $color-main04;
                    }
                }
            }
        }
    }
    .pagination {
        padding: 0;
        margin-top: 37px;
    }
}
</style>
