import { devices, connetionList } from '@/data/connetionList';
import ConnectionUpdatePopup from '@/components/popup/setting/ConnectionUpdate';
import DeleteConfirmPopup from '@/components/popup/common/DeleteConfirm';
import PagePath from '@/components/widget/PagePath';

import * as LogUtil from '@/common/LogUtil';
import * as Device from '@/rest/Device';

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
        PagePath,
        ConnectionUpdatePopup,
        DeleteConfirmPopup,
        AlertModal,
    },
    data: () => ({
        alertModalParams: { isOpened: false, title: '', message: '' },

        pageNo: 1,
        cateNum: -1,
        pageSize: 10,
        isUpdatePopupOpen: false,
        isDeletePopupOpen: false,
        isConfirmOpen: {
            view: true,
            title: 'update_fail',
        },
        deviceTypeList: [
            { value: 'D', label: '드론돔' },
            { value: 'R', label: '레이더' },
            { value: 'J', label: '재머' },
            { value: 'S', label: '스캐너' },
            { value: 'E', label: 'EO/IR' },
            { value: 'P', label: '스푸퍼' },
        ],
        selectInfo: {},
        headers: [
            { text: '이름', value: 'DEVICE_NAME', sortable: false },
            { text: '연결방식', value: 'CONNECT_TYPE', sortable: false },
            { text: '장치 IP', value: 'DEVICE_IP', sortable: false },
            { text: '장치 Port', value: 'DEVICE_PORT', sortable: false },
            { text: '전원 IP', value: 'POWER_IP', sortable: false },
            { text: '전원 Port', value: 'POWER_PORT', sortable: false },
            { text: 'PC Port', value: 'PC_PORT', sortable: false },
            { text: '장 비', value: 'DEVICE_TYPE', sortable: false },
            { text: '버 전', value: 'VERSION' },
            { text: '상 태', value: 'STATUS' },
        ],
        dataList: [],
        selectedDeviceType: 'A',
    }),
    computed: {
        numOfPages() {
            const data = this.dataList.length;
            return Math.ceil(data / this.pageSize);
        },
    },
    beforeMount() {
        this.devices = devices;
        // this.dataList = connetionList.reverse();
        this.initDataList(null);
    },
    methods: {
        showAlertModal(msg) {
            this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
        },
        onDeviceTypeSelected(deviceType) {
            this.selectedDeviceType = deviceType;
            LogUtil.debug('onDeviceTypeSelected(): deviceType=', deviceType);
            // console.log('deviceType', deviceType);
            if (deviceType == 'A') {
                this.cateNum = -1;
            } else if (deviceType == 'D') {
                this.cateNum = 0;
            } else if (deviceType == 'R') {
                this.cateNum = 1;
            } else if (deviceType == 'J') {
                this.cateNum = 2;
            } else if (deviceType == 'S') {
                this.cateNum = 3;
            } else if (deviceType == 'E') {
                this.cateNum = 4;
            } else if (deviceType == 'P') {
                this.cateNum = 5;
            }

            if (deviceType != null && deviceType != 'A') {
                this.initDataList({ clause: 'and', name: 'DEVICE_TYPE', operator: '=', value: deviceType });
            } else {
                this.initDataList(null);
            }
        },
        selectList(select) {
            if (this.selectInfo === select) this.selectInfo = {};
            else this.selectInfo = select;
        },
        popupUpdateView(view) {
            this.isUpdatePopupOpen = view;
        },
        onUpdate() {
            this.isUpdatePopupOpen = false;
            this.initDataList();
        },
        onUpdateCancel() {
            this.isUpdatePopupOpen = false;
        },
        popupDeleteView(view) {
            this.isDeletePopupOpen = view;
        },
        onDelete() {
            this.isDeletePopupOpen = false;
            if (this.selectInfo.DEVICE_ID !== undefined) {
                Device.deleteOne({
                    DEVICE_ID: this.selectInfo.DEVICE_ID,
                })
                    .then((res) => {
                        if (res.data.RES_CODE >= 0) {
                            LogUtil.debug('res.data.RES_CODE=', res.data.RES_CODE);
                            this.selectInfo = {};
                            this.isDeletePopupOpen = false;
                            this.initDataList();
                        } else {
                            this.showAlertModal(res.data.RES_MSG);
                        }
                    })
                    .catch((e) => {
                        LogUtil.error('error=', e);
                        this.showAlertModal(e);
                    })
                    .finally(() => {});
            }
        },
        onDeleteCancel() {
            this.isDeletePopupOpen = false;
        },
        initDataList(condition) {
            let options = {
                conditions: [
                    // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
                ],
                orderBys: [{ name: 'DEVICE_NAME', operator: 'asc' }],
                paging: { pageNo: 1, pageSize: 100 },
            };
            if (condition != null) options.conditions.push(condition);

            Device.listByCondition(options)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        this.dataList = res.data.ITEMS;
                        LogUtil.debug('this.dataList=', this.dataList);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
        getDeviceType(type) {
            switch (type) {
                case 'D':
                    return '드론돔';
                case 'R':
                    return '레이더';
                case 'J':
                    return '재머';
                case 'S':
                    return '스캐너';
                case 'E':
                    return 'EO/IR';
                case 'P':
                    return '스푸퍼';
            }
        },
    },
};
